listitem.para:
event_nats — publishes &osips;
events and script payloads to NATS subjects,
optionally via JetStream async publish.

cachedb_nats — exposes NATS
Key-Value buckets through the &osips;
cachedb interface.

example.programlisting:
route[PROCESS] {
    async(nats_fetch("orders", 5000), ON_MSG);
}

route[ON_MSG] {
    if ($retcode == 1) {
        xlog("L_INFO", "got $nats_subject: $nats_data\n");
        nats_ack();
    } else {
        xlog("L_WARN", "no message, rc=$retcode\n");
    }
}

timer_route[drain] {
    $var(n) = nats_fetch_batch("jobs", "count=10;expires=2s");
    $var(i) = 0;
    while ($var(i) < $var(n)) {
        nats_batch_select($var(i));
        xlog("L_INFO", "job $nats_seq: $nats_data\n");
        nats_ack();
        $var(i) = $var(i) + 1;
    }
}

startup_route {
    nats_consumer_bind(
        "id=jobs;stream=WORK;durable=jobs_worker;"
        "filter=work.jobs;ack_wait=30s;max_deliver=5");
}

timer_route[drain, 1] {
    while (nats_fetch("jobs", 250) > 0) {
        xlog("L_INFO", "job $nats_seq: $nats_data\n");
        nats_ack_next();
    }
}

startup_route {
    nats_consumer_bind(
        "id=dlq;stream=_SYS_JS;ephemeral=1;"
        "filter=$JS.EVENT.ADVISORY.MAX_DELIVERIES.>;"
        "inactive_threshold=5m");
}

timer_route[check_dlq, 5] {
    while (nats_fetch("dlq", 100) > 0) {
        xlog("L_ALERT", "dead letter: $nats_subject $nats_data\n");
        nats_ack();
    }
}

startup_route {
    nats_consumer_bind(
        "id=rpc_srv;stream=RPC;durable=srv;"
        "filter=rpc.call;ack_wait=5s");
}

timer_route[rpc_srv, 1] {
    while (nats_fetch("rpc_srv", 100) > 0) {
        nats_hdr_set("X-Trace-Id", "$nats_hdr(X-Trace-Id)");
        if (nats_reply("echo: $nats_data"))
            nats_ack();
        else
            nats_nak();
    }
}

timer_route[rpc_cli, 5] {
    if (nats_request("rpc.call", "ping", 2000))
        xlog("L_INFO", "reply: $nats_data\n");
}
